import React, { useState, useEffect } from 'react';
import { Switch, Route, Redirect } from 'react-router-dom';
import './style/style.scss';

/* Bootstrap */
import 'bootstrap/dist/css/bootstrap.min.css';

/* Components */
import Home from './components/Home';
import Login from './components/admin/Login';

/* FA */
import { library } from '@fortawesome/fontawesome-svg-core'
import { fab } from '@fortawesome/free-brands-svg-icons';

library.add(fab);

const App = () => {

  const [active, setActive] = useState({
    home: true,
    work: false,
    about: false,
    contact: false,
  });

  useEffect(() => {
    let scrollpos = window.scrollY;
    const header = document.querySelector('#navigation');
    const header_home_height = header.offsetHeight+header.offsetHeight;
    const header_height = header.offsetHeight;

    const h_work = document.getElementById('work');
    const h_work_height = (h_work.offsetHeight+header_home_height);

    const h_about = document.getElementById('about');
    const h_about_height = (h_about.offsetHeight+h_work_height);

    const h_contact = document.getElementById('contact');
    const h_contact_height = (h_contact.offsetHeight+h_about_height);

    const add_class_on_scroll = () => header.classList.add('shadow');
    const remove_class_on_scroll = () => header.classList.remove('shadow');

    const idle_nav_pad = () => header.classList.add('idle-nav-pad');
    const new_nav_pad = () => header.classList.add('new-nav-pad');
    const idle_nav_pad_rv = () => header.classList.remove('idle-nav-pad');
    const new_nav_pad_rv = () => header.classList.remove('new-nav-pad');

    window.addEventListener('scroll', () => {
        scrollpos = window.scrollY;

        if (scrollpos >= header_height) {
            add_class_on_scroll();
            new_nav_pad();
            idle_nav_pad_rv();
        } else {
            remove_class_on_scroll();
            idle_nav_pad();
            new_nav_pad_rv();
        }

        //hardcoded effect
        if(scrollpos<=header_home_height) {
            setActive({
              home: true,
              work: false,
              about: false,
              contact: false,
            });
        } else if(scrollpos<=h_work_height) {
            setActive({
              home: false,
              work: true,
              about: false,
              contact: false,
            });
        } else if(scrollpos<=h_about_height) {
            setActive({
              home: false,
              work: false,
              about: true,
              contact: false,
            });
        } else if(scrollpos<=h_contact_height) {
          setActive({
            home: false,
            work: false,
            about: false,
            contact: true,
          });
      }
    });
  }, [])
  
  return (
    <>
    <Switch>
      <Route exact path="/">
        <Home isActive={active}/>
      </Route>
      <Route path="/login">
        <Login />
      </Route>
      <Route path="*" render={ () => <Redirect to="/" /> }/>
    </Switch>
    </>
  );
}

export default App;
