import React, { useState } from 'react';

/* Bootstrap */
import Container from 'react-bootstrap/Container';
import Button from 'react-bootstrap/Button';

/* Sub Components */
import Card from './sub/Cards';

const Work = () => {
    const [visible, setVisibility] = useState(false);
    const showProjects = () => {
        visible ? setVisibility(false) : setVisibility(true);
    }
    
    return(
        <Container>
            <div className="section" id="work">
                <div className="section-title"><span className="section-number">01</span>&nbsp;Work</div>
                <div className="centered-text">
                    <h1>Top Projects</h1>
                </div>
                <div className="content">
                    <div className="cards">
                        <Card />
                        <Card />
                        <Card />
                    </div>
                    <div className="centered-text">
                        <h4>Other Notable Projects</h4>
                        {/* other notable works here */}
                        { visible ? <Other /> : '' }
                        <Button size="lg" variant="outline-info" className="btn-cstm" onClick={showProjects}>{ visible ? 'Hide' : 'Show' } projects</Button>{' '}
                    </div>
                </div>
            </div>
        </Container>
    );
}

const Other = () => (
<div id="other" className="mb-5">
    other projects here
</div>
)

export default Work;