import React, { useState } from 'react';
import axios from 'axios';

/* Bootstrap */
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import Form from 'react-bootstrap/Form';
import Button from 'react-bootstrap/Button';

const Contact = () => {
    const [state, setState] = useState({
        email: '',
        honeypot: '',
        subject: 'Say Hi!',
        message: ''
    })

    const { email, honeypot, subject, message } = state;

    const inputOnChange = (e) => {
        const { name, value } = e.target

        setState({...state, [name]: value})
    }

    const [disable, setDisable] = useState(false);
    const [required, setRequired] = useState(false);
    const [notification,setNotification] = useState(false);

    const sendMessage = (e) => {

        e.preventDefault();
        disable ? setDisable(false): setDisable(true);

        const mailOptions = {
            email: email,
            honeypot: honeypot,
            subject: subject,
            message: message
        }

        const validateEmail = (mail) => {
            const re = /^(([^<>()[\]\\.,;:\s@]+(\.[^<>()[\]\\.,;:\s@]+)*)|(.+))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
            return re.test(mail);
        }

        if(mailOptions.honeypot === '' && validateEmail(mailOptions.email) && mailOptions.message !== '') {
            setRequired(false);
            axios.post('https://justinbalaguer-mailing.herokuapp.com/api', mailOptions)
                .then(res => {
                        console.log(res.data);
                        setState({...state,email: '',message: ''})
                        setDisable(false);
                        setNotification(true);
                        setTimeout(() => {
                            setNotification(false);
                        }, 3000);
                    })
                .catch(res => console.log("Bad Request"))
        } else if(mailOptions.honeypot !== '') {
            alert('bot detected');
            setDisable(false);
            setNotification(false);
        } else if(validateEmail(mailOptions.email)===false || mailOptions.message === '') {
            setRequired(true);
            setDisable(false);
            setNotification(false);
        }

    }

    return(
        <Container>
            <div className="section" id="contact">
                <div className="section-title"><span className="section-number">03</span>&nbsp;Contact</div>
                <div className="centered-text">
                    <h1>Let's connect</h1>
                </div>
                <div className="form-wrapper">
                    <Form id="contact-form">
                        <Row>
                            <Col>
                                <div className={ notification ? 'notification-container' : ''}>
                                    <b className="notification-message">{ notification ? 'Message sent!' : '' }</b>
                                </div>
                            </Col>
                        </Row>
                        <Row>
                            <Col sm={6}>
                                <Form.Group controlId="email">
                                    <Form.Label>Email address { required ? <span className="text-danger">*</span> : '' }</Form.Label>
                                    <Form.Control size="lg" type="email" name="email" onChange={inputOnChange} value={email} />
                                </Form.Group>
                                <Form.Group controlId="honeypot" className="honeypot">
                                    <Form.Control size="lg" type="text" name="honeypot" onChange={inputOnChange} value={honeypot} />
                                </Form.Group>
                            </Col>
                            <Col sm={6}>
                            <Form.Group controlId="subject">
                                <Form.Label>Subject</Form.Label>
                                <Form.Control size="lg" as="select" name="subject" className="select" onChange={inputOnChange} >
                                    <option>Say Hi!</option>
                                    <option>Business</option>
                                </Form.Control>
                            </Form.Group>
                            </Col>
                        </Row>
                        <Row>
                            <Col>
                                <Form.Group controlId="message">
                                    <Form.Label>Message { required ? <span className="text-danger">*</span> : '' }</Form.Label>
                                    <Form.Control size="lg" as="textarea" name="message" value={message} rows="5" onChange={inputOnChange} />
                                </Form.Group>
                            </Col>
                        </Row>
                        <Row>
                            <Col>
                                <Button onClick={sendMessage} disabled={disable} className="mr-3 mt-2 btn btn-info btn-cstm btn-block" >{disable ? 'Sending...' : 'Send message'}</Button>{' '}
                            </Col>
                        </Row>
                    </Form>
                </div>
            </div>
        </Container>
    );
}

export default Contact;